# Index articles by ID
articles_map = {str(a['article_id']): a for a in articles_list}

# Join
joined_data = []
for m in metadata_list:
    aid = str(m['article_id'])
    if aid in articles_map:
        art = articles_map[aid]
        joined_data.append({
            'article_id': aid,
            'region': m['region'],
            'title': art.get('title', ''),
            'description': art.get('description', '')
        })

